// Map each stack item (exact label from site.ts) to its brand mark.
// Items with no real logo (concepts, AWS sub-services w/o a mark) are omitted
// and render as text-only chips.
const LOGOS: Record<string, Glyph> = {
  Go: si(siGo),
  Java: si(siOpenjdk),
  JavaScript: si(siJavascript),
  TypeScript: si(siTypescript),
  Python: si(siPython),
  C: si(siC),
  'Spring Boot': si(siSpringboot),
  'Spring Cloud': si(siSpring),
  'Spring Security': si(siSpringsecurity),
  'Node.js': si(siNodedotjs),
  'Apache Kafka': si(siApachekafka),
  AWS,
  EC2,
  S3,
  'Microsoft Azure': AZURE,
  Terraform: si(siTerraform),
  Docker: si(siDocker),
  Kubernetes: si(siKubernetes),
  'GitLab CI': si(siGitlab),
  'GitHub Actions': si(siGithubactions),
  Bamboo: si(siBamboo),
  Bitbucket: si(siBitbucket),
  Angular: si(siAngular),
  React: si(siReact),
  'React Native': si(siReact),
  Ionic: si(siIonic),
  HTML: si(siHtml5),
  CSS: si(siCss),
  Grafana: si(siGrafana),
  Cucumber: si(siCucumber),
  Gherkin: si(siCucumber),
  JUnit: si(siJunit5),
  PostgreSQL: si(siPostgresql),
  MySQL: si(siMysql),
  MongoDB: si(siMongodb),
  Oracle: ORACLE,
  // Also used as Experience / Projects tags:
  Flask: si(siFlask),
  Elasticsearch: si(siElasticsearch),
  Stripe: si(siStripe),
  PayPal: si(siPaypal),
}

// Tag strings that carry extra qualifiers still resolve to their brand mark.
const ALIASES: Record<string, string> = {
  Azure: 'Microsoft Azure',
  'Flask / Python': 'Flask',
  'AWS (SNS · SQS · S3)': 'AWS',
  'AWS Textract': 'AWS',
  'Docker Compose': 'Docker',
}

function resolve(name: string): Glyph | undefined {
  return LOGOS[name] ?? (ALIASES[name] ? LOGOS[ALIASES[name]] : undefined)
}

export function hasTechLogo(name: string): boolean {
  return resolve(name) !== undefined
}

type TechLogoProps = { name: string } & SVGProps<SVGSVGElement>

/** Brand mark for a stack item, in its official colour. Renders nothing for
 *  items without a real logo (concepts like "Microservices"). */
export function TechLogo({ name, ...props }: TechLogoProps) {
  const logo = resolve(name)
  if (!logo) return null
  return (
    <svg viewBox="0 0 24 24" fill={`#${logo.hex}`} aria-hidden {...props}>
      <path d={logo.path} />
    </svg>
  )
}
